import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * REORDER - a reorder cost over an INDEXED BY price table, translated from
 * COBOL 85. Faithful variant: exact COBOL behavior over Java idiom.
 *
 * WS-PRICE PIC 9(3)V99 OCCURS 5 INDEXED BY PX is a 1-based price table
 * filled at literal subscripts and summed by iterating the index. The
 * index PX is an occurrence-number variable: SET PX TO 1 then SET PX UP
 * BY 2 selects occurrence 3. The 5% reorder fee is ROUNDED to the cent.
 */
public final class Reorder {

    /** PIC 9(5)V99 capacity (WS-QTY). */
    private static final BigDecimal PIC_9_5_V99 = new BigDecimal("100000");
    /** PIC 9(5)V99 capacity (WS-SUMP). */
    private static final BigDecimal PIC_9_5_V99_SUMP = new BigDecimal("100000");
    /** PIC 9(7)V99 capacity (WS-BASE / WS-FEE / WS-TOTAL). */
    private static final BigDecimal PIC_9_7_V99 = new BigDecimal("10000000");
    /** COMPUTE WS-FEE ROUNDED = WS-BASE * 5 / 100. */
    private static final BigDecimal RATE = new BigDecimal("5");
    private static final BigDecimal HUNDRED = new BigDecimal("100");
    /** IF WS-TOTAL > 500. */
    private static final BigDecimal THRESHOLD = new BigDecimal("500");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal qty = numval(in.readLine()); // WS-QTY = NUMVAL(WS-QTY-TEXT)

        // WS-PRICE OCCURS 5 INDEXED BY PX, 1-based (index 0 unused).
        BigDecimal[] price = new BigDecimal[6];
        price[1] = new BigDecimal("1.20");
        price[2] = new BigDecimal("1.55");
        price[3] = new BigDecimal("1.75");
        price[4] = new BigDecimal("2.00");
        price[5] = new BigDecimal("0.90");

        // PERFORM SUMP-PARA VARYING PX FROM 1 BY 1 UNTIL PX > 5.
        BigDecimal sump = BigDecimal.ZERO; // WS-SUMP PIC 9(5)V99 VALUE ZERO
        for (int px = 1; px <= 5; px = px + 1) {
            sump = sump.add(price[px]).remainder(PIC_9_5_V99_SUMP);
        }

        // SET PX TO 1; SET PX UP BY 2  ->  occurrence 3.
        int px = 1;
        px = px + 2;
        BigDecimal base = qty.multiply(price[px]).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_7_V99); // WS-BASE = WS-QTY * WS-PRICE(PX)
        BigDecimal fee = base.multiply(RATE).divide(HUNDRED)
                .setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_7_V99);          // WS-FEE ROUNDED
        BigDecimal total = base.add(fee).remainder(PIC_9_7_V99);                    // WS-TOTAL
        String tier = total.compareTo(THRESHOLD) > 0 ? "BULK" : "STD ";

        StringBuilder out = new StringBuilder();
